/**
 * Defines the possible abi call signatures.
 */
export type RaffleSignatures = keyof RaffleTypes['methods']
/**
 * Defines the possible abi call signatures for methods that return a non-void value.
 */
export type RaffleNonVoidMethodSignatures = keyof RaffleTypes['methods'] extends infer T ? T extends keyof RaffleTypes['methods'] ? MethodReturn<T> extends void ? never : T  : never : never
/**
 * Defines an object containing all relevant parameters for a single call to the contract.
 */
export type CallParams<TArgs> = Expand<
  Omit<AppClientMethodCallParams, 'method' | 'args' | 'onComplete'> &
    {
      /** The args for the ABI method call, either as an ordered array or an object */
      args: Expand<TArgs>
    }
>
/**
 * Maps a method signature from the Raffle smart contract to the method's arguments in either tuple or struct form
 */
export type MethodArgs<TSignature extends RaffleSignatures> = RaffleTypes['methods'][TSignature]['argsObj' | 'argsTuple']
/**
 * Maps a method signature from the Raffle smart contract to the method's return type
 */
export type MethodReturn<TSignature extends RaffleSignatures> = RaffleTypes['methods'][TSignature]['returns']

/**
 * Defines the shape of the keyed global state of the application.
 */
export type GlobalKeysState = RaffleTypes['state']['global']['keys']

/**
 * Defines the shape of the keyed box state of the application.
 */
export type BoxKeysState = RaffleTypes['state']['box']['keys']


/**
 * Defines supported create method params for this smart contract
 */
export type RaffleCreateCallParams =
  | Expand<CallParams<RaffleArgs['obj']['create(uint64,bool,uint64,uint64,uint64,address,(address,uint64),uint64,uint64,uint64,uint64,address,uint64,(string,uint64))void'] | RaffleArgs['tuple']['create(uint64,bool,uint64,uint64,uint64,address,(address,uint64),uint64,uint64,uint64,uint64,address,uint64,(string,uint64))void']> & {method: 'create'} & { onComplete?: OnApplicationComplete.NoOp } & CreateSchema>
  | Expand<CallParams<RaffleArgs['obj']['create(uint64,bool,uint64,uint64,uint64,address,(address,uint64),uint64,uint64,uint64,uint64,address,uint64,(string,uint64))void'] | RaffleArgs['tuple']['create(uint64,bool,uint64,uint64,uint64,address,(address,uint64),uint64,uint64,uint64,uint64,address,uint64,(string,uint64))void']> & {method: 'create(uint64,bool,uint64,uint64,uint64,address,(address,uint64),uint64,uint64,uint64,uint64,address,uint64,(string,uint64))void'} & { onComplete?: OnApplicationComplete.NoOp } & CreateSchema>
